parsed.api_descriptions:
API_name: nchu_cross_program_search_by_keyword
Description:
{
  "description": "依關鍵字搜尋中興大學學分學程（跨領域學程）課程，支援指定學期與學制（大學部/研究生）。",
  "required_parameters": [
    {
      "name": "keyword",
      "type": "STRING",
      "description": "搜尋關鍵字"
    }
  ],
  "optional_parameters": [
    {
      "name": "limit",
      "type": "NUMBER",
      "description": "回傳結果上限",
      "default": 10
    },
    {
      "name": "semester",
      "type": "STRING",
      "description": "學年期代碼（如 1142）",
      "default": null
    },
    {
      "name": "degree_type",
      "type": "STRING",
      "description": "學制：U=大學部, G=研究生",
      "default": null
    },
    {
      "name": "include_syllabus_search",
      "type": "BOOLEAN",
      "description": "是否同時搜尋大綱內容",
      "default": false
    }
  ]
}

